settings.liquid:
{% comment %}
  =====================================================
  360 SPIN FEATURE - ADD THIS TO CUSTOM LIQUID BLOCK
  =====================================================

  INSTRUCTIONS:
  1. Go to Theme Customizer > Product Page
  2. Add a "Custom Liquid" block under the Media block
  3. Paste this entire code
  4. Remove any old 360 spin code you added before
{% endcomment %}

{% assign spin360_enabled = true %}
{% assign spin360_image_count = 12 %}
{% assign spin360_sensitivity = 8 %}

{% if spin360_enabled and product.images.size >= 2 %}
<style>
/* ========== 360 SPIN OVERLAY STYLES ========== */
.spin360-viewer-overlay {
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  width: 100% !important;
  height: 100% !important;
  background: #fff !important;
  z-index: 100 !important;
  display: none;
  cursor: grab;
  touch-action: pan-y;
}

.spin360-viewer-overlay.spin360-active {
  display: flex !important;
  align-items: center;
  justify-content: center;
}

.spin360-viewer-overlay:active,
.spin360-viewer-overlay.spin360-dragging {
  cursor: grabbing;
}

/* 360 Image */
.spin360-viewer-overlay .spin360-main-img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: contain;
  pointer-events: none;
  user-select: none;
  -webkit-user-drag: none;
}

/* Badge */
.spin360-viewer-overlay .spin360-viewer-badge {
  position: absolute;
  top: 12px;
  left: 12px;
  background: #0047AB;
  color: #fff;
  font-size: 12px;
  font-weight: 700;
  padding: 8px 14px;
  border-radius: 20px;
  z-index: 110;
  display: flex;
  align-items: center;
  gap: 6px;
  box-shadow: 0 2px 10px rgba(0,71,171,0.3);
  pointer-events: none;
}

.spin360-viewer-overlay .spin360-viewer-badge svg {
  width: 16px;
  height: 16px;
  animation: spin360BadgeRotate 3s linear infinite;
}

@keyframes spin360BadgeRotate {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

/* Drag Hint */
.spin360-viewer-overlay .spin360-drag-hint {
  position: absolute;
  bottom: 16px;
  left: 50%;
  transform: translateX(-50%);
  background: rgba(0,0,0,0.75);
  color: #fff;
  padding: 8px 16px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 500;
  z-index: 110;
  pointer-events: none;
  transition: opacity 0.3s;
  display: flex;
  align-items: center;
  gap: 6px;
}

.spin360-viewer-overlay .spin360-drag-hint.spin360-hint-hidden {
  opacity: 0;
}

/* Loading */
.spin360-viewer-overlay .spin360-loading-box {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(255,255,255,0.95);
  padding: 16px 24px;
  border-radius: 10px;
  box-shadow: 0 4px 20px rgba(0,0,0,0.15);
  z-index: 120;
  display: flex;
  align-items: center;
  gap: 12px;
}

.spin360-viewer-overlay .spin360-loading-box.spin360-loading-done {
  display: none;
}

.spin360-viewer-overlay .spin360-loading-spinner {
  width: 24px;
  height: 24px;
  border: 3px solid #eee;
  border-top-color: #0047AB;
  border-radius: 50%;
  animation: spin360LoadSpin 0.6s linear infinite;
}

@keyframes spin360LoadSpin {
  to { transform: rotate(360deg); }
}

/* Close Button */
.spin360-viewer-overlay .spin360-close-btn {
  position: absolute;
  top: 12px;
  right: 12px;
  width: 36px;
  height: 36px;
  background: rgba(0,0,0,0.6);
  border: none;
  border-radius: 50%;
  color: #fff;
  cursor: pointer;
  z-index: 115;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s;
  pointer-events: auto;
}

.spin360-viewer-overlay .spin360-close-btn:hover {
  background: rgba(0,0,0,0.8);
}

/* ========== THUMBNAIL 360 BADGE ========== */
.hdt-thumbnail__media:first-child .spin360-thumb-badge-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0,71,171,0.85);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  border-radius: 4px;
  cursor: pointer;
  z-index: 5;
}

.hdt-thumbnail__media:first-child .spin360-thumb-badge-overlay svg {
  width: 24px;
  height: 24px;
  color: #fff;
}

.hdt-thumbnail__media:first-child .spin360-thumb-badge-overlay span {
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
}

/* First slide indicator */
.hdt-slider__slide.hdt-product__media-item:first-child {
  position: relative;
}
</style>

<script>
(function() {
  'use strict';

  // Prevent duplicate initialization
  if (window.Spin360ViewerInitialized) return;
  window.Spin360ViewerInitialized = true;

  var CONFIG = {
    sensitivity: {{ spin360_sensitivity }},
    images: [
      {% for image in product.images limit: spin360_image_count %}
      "{{ image | image_url: width: 1200 }}"{% unless forloop.last %},{% endunless %}
      {% endfor %}
    ]
  };

  console.log('[Spin360] Config loaded, images:', CONFIG.images.length);

  var state = {
    currentFrame: 0,
    isDragging: false,
    lastX: 0,
    velocity: 0,
    imagesLoaded: 0,
    allReady: false,
    preloaded: []
  };

  var elements = {
    overlay: null,
    image: null,
    hint: null,
    loader: null,
    progress: null
  };

  function createOverlay() {
    // Find the first slide in the main slider
    var firstSlide = document.querySelector('.hdt-slider__slide.hdt-product__media-item:first-child, .hdt-slider__slide.hdt-product__media-item[data-media-type="image"]:first-of-type');

    if (!firstSlide) {
      console.log('[Spin360] Waiting for slider...');
      setTimeout(createOverlay, 300);
      return;
    }

    // Check if overlay already exists
    if (firstSlide.querySelector('.spin360-viewer-overlay')) {
      console.log('[Spin360] Overlay already exists');
      return;
    }

    console.log('[Spin360] Creating overlay on first slide');

    // Create overlay HTML
    var overlay = document.createElement('div');
    overlay.className = 'spin360-viewer-overlay';
    overlay.id = 'spin360-overlay';
    overlay.innerHTML = [
      '<div class="spin360-viewer-badge">',
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">',
          '<path d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/>',
          '<path d="M9 12l2 2 4-4"/>',
        '</svg>',
        '360° View',
      '</div>',
      '<img class="spin360-main-img" id="spin360-main-img" src="' + CONFIG.images[0] + '" alt="360 View">',
      '<div class="spin360-drag-hint" id="spin360-drag-hint">',
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14">',
          '<path d="M5 12h14M5 12l3-3m-3 3l3 3m11-3l-3-3m3 3l-3 3"/>',
        '</svg>',
        'Drag to rotate',
      '</div>',
      '<div class="spin360-loading-box" id="spin360-loading-box">',
        '<div class="spin360-loading-spinner"></div>',
        '<span id="spin360-loading-progress">Loading...</span>',
      '</div>',
      '<button class="spin360-close-btn" id="spin360-close-btn" title="Close 360 View">',
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20">',
          '<path d="M18 6L6 18M6 6l12 12"/>',
        '</svg>',
      '</button>'
    ].join('');

    firstSlide.style.position = 'relative';
    firstSlide.appendChild(overlay);

    // Store element references
    elements.overlay = overlay;
    elements.image = document.getElementById('spin360-main-img');
    elements.hint = document.getElementById('spin360-drag-hint');
    elements.loader = document.getElementById('spin360-loading-box');
    elements.progress = document.getElementById('spin360-loading-progress');

    // Setup close button
    var closeBtn = document.getElementById('spin360-close-btn');
    if (closeBtn) {
      closeBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        deactivate360();
      });
    }

    // Add 360 badge to first thumbnail
    addThumbnailBadge();

    // Preload images
    preloadImages();

    // Setup drag events
    setupDragEvents();

    // Watch for slide changes
    watchSlideChanges(firstSlide);

    console.log('[Spin360] Overlay created successfully');
  }

  function addThumbnailBadge() {
    var firstThumb = document.querySelector('.hdt-thumbnail__media:first-child');
    if (!firstThumb) return;

    // Check if badge already exists
    if (firstThumb.querySelector('.spin360-thumb-badge-overlay')) return;

    var badge = document.createElement('div');
    badge.className = 'spin360-thumb-badge-overlay';
    badge.innerHTML = [
      '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">',
        '<circle cx="12" cy="12" r="10"/>',
        '<path d="M12 6v6l4 2"/>',
      '</svg>',
      '<span>360°</span>'
    ].join('');

    firstThumb.style.position = 'relative';
    firstThumb.appendChild(badge);

    badge.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      activate360();
    });
  }

  function preloadImages() {
    CONFIG.images.forEach(function(url, index) {
      var img = new Image();
      img.onload = function() {
        state.preloaded[index] = img;
        state.imagesLoaded++;

        var pct = Math.round((state.imagesLoaded / CONFIG.images.length) * 100);
        if (elements.progress) {
          elements.progress.textContent = pct + '%';
        }

        if (state.imagesLoaded === CONFIG.images.length) {
          state.allReady = true;
          if (elements.loader) {
            elements.loader.classList.add('spin360-loading-done');
          }
          console.log('[Spin360] All images preloaded!');
        }
      };
      img.onerror = function() {
        state.imagesLoaded++;
        console.warn('[Spin360] Failed to load:', url);
      };
      img.src = url;
    });
  }

  function activate360() {
    if (elements.overlay) {
      elements.overlay.classList.add('spin360-active');
      if (elements.hint) elements.hint.classList.remove('spin360-hint-hidden');
    }
    console.log('[Spin360] Activated');
  }

  function deactivate360() {
    if (elements.overlay) {
      elements.overlay.classList.remove('spin360-active');
    }
    console.log('[Spin360] Deactivated');
  }

  function watchSlideChanges(firstSlide) {
    // Watch for when first slide becomes active
    var observer = new MutationObserver(function(mutations) {
      mutations.forEach(function(mutation) {
        if (mutation.attributeName === 'class') {
          var isFirstActive = firstSlide.classList.contains('is-selected') || 
                              firstSlide.classList.contains('is-in-view');

          if (isFirstActive && !elements.overlay.classList.contains('spin360-active')) {
            // Auto-activate when returning to first slide
            activate360();
          }
        }
      });
    });

    observer.observe(firstSlide, { attributes: true });

    // Watch other slides - deactivate when moving away
    var allSlides = document.querySelectorAll('.hdt-slider__slide.hdt-product__media-item');
    allSlides.forEach(function(slide, index) {
      if (index === 0) return; // Skip first slide

      var slideObserver = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
          if (mutation.attributeName === 'class') {
            if (slide.classList.contains('is-selected')) {
              deactivate360();
            }
          }
        });
      });

      slideObserver.observe(slide, { attributes: true });
    });

    // Initial activation if first slide is active
    if (firstSlide.classList.contains('is-selected') || firstSlide.classList.contains('is-in-view')) {
      setTimeout(activate360, 100);
    }
  }

  function setupDragEvents() {
    var overlay = elements.overlay;
    if (!overlay) return;

    // Mouse events
    overlay.addEventListener('mousedown', onDragStart);
    document.addEventListener('mousemove', onDragMove);
    document.addEventListener('mouseup', onDragEnd);

    // Touch events
    overlay.addEventListener('touchstart', onTouchStart, { passive: false });
    overlay.addEventListener('touchmove', onTouchMove, { passive: false });
    overlay.addEventListener('touchend', onTouchEnd);
  }

  function onDragStart(e) {
    if (!state.allReady) return;
    if (e.target.classList.contains('spin360-close-btn') || e.target.closest('.spin360-close-btn')) return;

    state.isDragging = true;
    state.lastX = e.clientX;
    state.velocity = 0;

    elements.overlay.classList.add('spin360-dragging');
    if (elements.hint) elements.hint.classList.add('spin360-hint-hidden');

    e.preventDefault();
    console.log('[Spin360] Drag started');
  }

  function onDragMove(e) {
    if (!state.isDragging) return;

    var deltaX = e.clientX - state.lastX;
    state.velocity = deltaX;
    updateFrame(deltaX);
    state.lastX = e.clientX;
  }

  function onDragEnd() {
    if (!state.isDragging) return;

    state.isDragging = false;
    elements.overlay.classList.remove('spin360-dragging');

    if (Math.abs(state.velocity) > 2) {
      applyInertia();
    }
    console.log('[Spin360] Drag ended');
  }

  function onTouchStart(e) {
    if (!state.allReady) return;
    if (e.target.classList.contains('spin360-close-btn') || e.target.closest('.spin360-close-btn')) return;

    state.isDragging = true;
    state.lastX = e.touches[0].clientX;
    state.velocity = 0;

    elements.overlay.classList.add('spin360-dragging');
    if (elements.hint) elements.hint.classList.add('spin360-hint-hidden');

    e.preventDefault();
  }

  function onTouchMove(e) {
    if (!state.isDragging) return;

    var deltaX = e.touches[0].clientX - state.lastX;
    state.velocity = deltaX;
    updateFrame(deltaX);
    state.lastX = e.touches[0].clientX;

    e.preventDefault();
  }

  function onTouchEnd() {
    if (!state.isDragging) return;

    state.isDragging = false;
    elements.overlay.classList.remove('spin360-dragging');

    if (Math.abs(state.velocity) > 2) {
      applyInertia();
    }
  }

  function updateFrame(delta) {
    var frameChange = Math.round(delta / CONFIG.sensitivity);
    state.currentFrame = (state.currentFrame - frameChange + CONFIG.images.length) % CONFIG.images.length;

    if (elements.image && CONFIG.images[state.currentFrame]) {
      elements.image.src = CONFIG.images[state.currentFrame];
    }
  }

  function applyInertia() {
    if (Math.abs(state.velocity) < 0.5) return;

    updateFrame(state.velocity);
    state.velocity *= 0.92;

    requestAnimationFrame(applyInertia);
  }

  // Initialize
  function init() {
    console.log('[Spin360] Initializing...');
    createOverlay();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function() {
      setTimeout(init, 300);
    });
  } else {
    setTimeout(init, 300);
  }

})();
</script>
{% endif %}
